    "source": "\"\"\"Escrow: trustless payment release by arbiter.\"\"\"\nowner: address\npayer: address\npayee: address\narbiter: address\namount: uint256\nreleased: bool\nrefunded: bool\n\n@event\nclass Released:\n    to: indexed(address)\n    amount: uint256\n\n@event\nclass Refunded:\n    to: indexed(address)\n    amount: uint256\n\n@external\ndef __init__(payee: address, arbiter: address):\n    self.payer = msg_sender\n    self.payee = payee\n    self.arbiter = arbiter\n    self.amount = msg_value\n    self.released = False\n    self.refunded = False\n\n@external\ndef release():\n    assert(msg_sender == self.arbiter, \"Not arbiter\")\n    assert(not self.released, \"Already released\")\n    assert(not self.refunded, \"Already refunded\")\n    self.released = True\n    self.Released(self.payee, self.amount)\n\n@external\ndef refund():\n    assert(msg_sender == self.arbiter, \"Not arbiter\")\n    assert(not self.released, \"Already released\")\n    assert(not self.refunded, \"Already refunded\")\n    self.refunded = True\n    self.Refunded(self.payer, self.amount)\n\n@external\n@view\ndef status() -> bool:\n    return self.released\n"
