    "category": "Core",
    "description": "Asset Registry: registry of approved tokens and assets.",
    "source": "\"\"\"Asset Registry: registry of approved tokens and assets.\"\"\"\nowner: address\nassets: Mapping[address, bool]\n\n@external\ndef __init__():\n    self.owner = msg_sender\n\n@external\ndef add_asset(asset: address):\n    assert(msg_sender == self.owner, \"Not owner\")\n    self.assets[asset] = True\n\n@external\n@view\ndef is_approved(asset: address) -> bool:\n    return self.assets[asset]\n"
